import React, { useState } from 'react';

const App = () => {
  const [events] = useState([{
    id: 1,
    name: 'Event 1',
    date: '2022-01-01'
  }, {
    id: 2,
    name: 'Event 2',
    date: '2022-01-02'
  }]);
  const [selectedEvent, setSelectedEvent] = useState(null);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-full max-w-sm p-4 bg-white rounded shadow">
        {events.map(event => (
          <div key={event.id} className="p-4 mb-4 bg-gray-100 rounded hover:bg-gray-200">
            <h2 className="text-lg font-bold mb-2" onClick={() => setSelectedEvent(event)}>
              {event.name}
            </h2>
            <p className="text-gray-600 mb-4">
              {event.date}
            </p>
            <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">
              View Details
            </button>
          </div>
        ))}
        {selectedEvent && (
          <div className="bg-white p-4 mb-4 rounded">
            <h2 className="text-lg font-bold mb-2">
              {selectedEvent.name}
            </h2>
            <p className="text-gray-600 mb-4">
              {selectedEvent.date}
            </p>
          </div>
        )}
        <div className="p-4 bg-gray-100 rounded shadow">
          <p className="text-gray-600 mb-4">
            Current Date/Time:
          </p>
        </div>
      </div>
    </div>
  );
};

export default App;
